// HMAC opcional + extrai event/tenant/data/delivery em campos planos.
const secret = $env.WEBHOOK_SECRET;
const headers = $json.headers || {};
const body = $json.body || {};
if (secret) {
  const crypto = require('crypto');
  const raw = JSON.stringify(body);
  const got = (headers['x-crm-signature'] || '').replace(/^sha256=/,'');
  const expected = crypto.createHmac('sha256', secret).update(raw).digest('hex');
  if (got !== expected) throw new Error('HMAC invalido');
}
return [{
  json: {
    event: body.event,
    tenantId: body.tenantId,
    occurredAt: body.occurredAt,
    deliveryId: headers['x-crm-delivery'] || null,
    data: body.data,
    raw: body
  }
}];
